package day3;

public class IfElseLadder {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int marks=80;
		if(marks>90)
		{
			System.out.println("A grade");
		}
		else if(marks>75)
		{
			System.out.println("B grade");
		}
		else
		{
			System.out.println("Fail");
		}

	}

}
